import React, { useEffect, useState, useRef } from "react";



import { getStore, updStore, gen16CodeId, qryKClient, fetchPostH, getUrlServerSide, ObjectKeys, compareJSON, qryStore, fetchEncryptStream } from "../../../stores/Utils";

import { CheckBoxSlide_Cmpt, TextInput_Cmpt, CheckBox_Cmpt, DropDwnPicker_Cmpt } from "../../../components";
import { OpenModal, CloseModal } from "../../../components/DialogHRM";



import DateCalComponent from "./DateCalComponent";
import PickClient from "./PickClient";


const TextInput = TextInput_Cmpt();



const CheckBoxSlide = CheckBoxSlide_Cmpt();


const DropDwnPicker = DropDwnPicker_Cmpt();


const frmNm = qryKClient()

const UpdClientInfo  = ({ data, elmId, confirm }) => {
	const [initialize, setInitialize] = useState(false);
	const [obs, set_obs] = useState(0);

	useEffect(() => {
		if (!initialize) {
			setInitialize(true);
			
			set_obs(gen16CodeId())
		}
	});

	const updFrm = (f, v, k) => {
		let frm2 = getStore(frmNm) || {};
		if(k){
			if( !frm2[k]){
				frm2[k] = {};
			}
			frm2[k][f] = v;
		}else{
			frm2[f] = v;
		}
		updStore(frmNm, frm2);
		
		set_obs(gen16CodeId())
	};


	const print  = async ()  => {
		let ffm = getStore(frmNm);

		if(ffm && ffm["dateOfBirth"]){
			let nd = (new Date(ffm["dateOfBirth"])).getTime();
			if(nd){
				ffm["dob"] = nd;
			}
		}
	

		let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )

		
		let bdyq2 = {...getStore(qryStore())?.upd_notary};
		bdyq2.params = {
			"clientNotaryId": ffm["clientNotaryId"]
		}
		bdyq2.data2update = diff.data;	
		
	

		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			updStore(frmNm, {});
			updStore(frmNm + "_bck", {});
			set_obs(gen16CodeId())
			close(true);
			confirm && confirm();
		}
		///let pdfUri = await generateTranslateAddClient(ffm, true, true);
		///window.open(pdfUri);
	};

	let flds = [
		"phoneNumber","email",
		"firstName","middleName", 
		"lastName","dateOfBirth",
		"genre","placeOfBirth",
		"currentLocation",
		"currentAddress", "father", "mother", 
		"height", "weight", "ss","alienNumber",
		"race","maritalStatus", 
		"ethnicity", "hairColor", "eyesColor",
		"spouse", "isDecease",
		"countryOfBirth",
		"countryOfCitizenship",
		"isInCourt", "isInUSA",
		"subjectId","citizenshipOrResidency",
		"includedOnApplication","counsel_provider_list",
		"family_help_preparing","someone_help_preparing",
		"marriage_date", "marriage_country", "marriage_state",
		"court_name", "court_city", "court_address", "judgeName"
	]

	let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )


	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}

	
	const handlePick = (v,f)=>{
		updFrm(f,v.clientNotaryId)
	}

	const handleDate = (k,v)=>{
		updFrm(k,v)
	}


	const openPick = (f)=>{
		let data = {};
		data["zIndex"] = 480;
		// data['observeResize']=true;
		data["props"] = { minHeight: "1vh", overlay: true };
		data["content"] = <PickClient handleClick={(v)=>handlePick(v,f) } />
		OpenModal(data);
	}




	return (
		<div style={{
			maxHeight: "80vh",
			width: "960px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title ">
					Actualizar Formulario Cliente
				</p>
				<div className="flexSpace"/>
				
			</div>

			

			<div className="_dsplFlx spaceAround flxWrp " style={{marginTop: 30}}>
			
					
					
				<div style={{margin:"10px 10px 0 0"}}>
						<DateCalComponent  
							init={getStore(frmNm)?.["dateOfBirth"]} 
							label={"Fecha de nacimiento"}
							updDate={(e)=>updFrm("dateOfBirth",e)}
						/>
					</div>
					<div className="flexSpace"/>
					
					<div style={{marginTop:10}}>
						<DropDwnPicker 
							init={getStore(frmNm)?.["citizenshipOrResidency"]}
							lbl_empty={"Citizenship or Residency"} 
							list={
								[
									{label: "None", id:null},
									{label: "U.S. Citizen.", id:"USC"},
									{label: "Permanent Resident.", id:"LPR"},
									
								]
							}
							onSelect={(e)=>updFrm("citizenshipOrResidency",e.id)} 
							background={"var(--dark-900)"}
							color={"var(--light-200)"}
						/>
					</div>
					<div className="flexSpace"/>
					
					<div className="_dsplFlx " style={{marginTop: 20}}>
						<CheckBoxSlide
							initvalue={getStore(frmNm)?.["includedOnApplication"]}
							keyCode={27}
							updChange={(e)=>updFrm("includedOnApplication",e)}
							color={"var(--primary)"}
						/>
						<span className={`checklabel`}>
							{"Incluir en la app"}
						</span>
					</div>
					
					<div className="flexSpace"/>
					
					<div className="_dsplFlx " style={{marginTop: 20}}>
						<CheckBoxSlide
							initvalue={getStore(frmNm)?.["isDecease"]}
							keyCode={22}
							updChange={(e)=>updFrm("isDecease",e)}
							color={"var(--primary)"}
						/>
						<span className={`checklabel`}>
							{"Fallecido"}
						</span>
					</div>
					<div className="flexSpace"/>
					
				</div>
			
			<div className="_dsplFlx spaceAround flxWrp " style={{marginTop: 30}}>
			
				
				<TextInput  
					init={getStore(frmNm)?.["firstName"]} 
					label={"Nombre"} 
					width={200} 
					updChanges={(e)=>updFrm("firstName",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["middleName"]} 
					label={"Segundo Nombre"} 
					width={200} 
					updChanges={(e)=>updFrm("middleName",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["lastName"]} 
					label={"Apellidos"} 
					width={360} 
					updChanges={(e)=>updFrm("lastName",e)}
				/>
				
			</div>


		
			<div className="_dsplFlx " style={{marginTop: 10}}>
				
				
				<TextInput  
					init={getStore(frmNm)?.["email"]} 
					label={"Email"} 
					width={360} 
					updChanges={(e)=>updFrm("email",e)}
				/>

				<div className="flexSpace"/>
				<TextInput  
					init={getStore(frmNm)?.["alienNumber"]} 
					label={"Alien Number"} 
					width={160} 
					updChanges={(e)=>updFrm("alienNumber",e)}
				/>
				
				<div className="flexSpace"/>
				<TextInput  
					init={getStore(frmNm)?.["subjectId"]} 
					label={"Subject Id"} 
					width={160} 
					updChanges={(e)=>updFrm("subjectId",e)}
				/>
				<div className="flexSpace"/>
				<TextInput  
					init={getStore(frmNm)?.["ss"]} 
					label={"Social"} 
					width={160} 
					updChanges={(e)=>updFrm("ss",e)}
				/>
				
				<div className="flexSpace"/>
			</div>



			<div className="_dsplFlx " style={{marginTop: 10}}>
				
				<TextInput  
					init={getStore(frmNm)?.["phoneNumber"]} 
					label={"Telefono"} 
					width={160} 
					updChanges={(e)=>updFrm("phoneNumber",e)}
				/>

				<div className="flexSpace"/>
				<TextInput  
					init={getStore(frmNm)?.["height"]} 
					label={"Altura"} 
					width={120} 
					updChanges={(e)=>updFrm("height",e)}
				/>
				<div className="flexSpace"/>
				<TextInput  
					init={getStore(frmNm)?.["weight"]} 
					label={"Peso"} 
					width={120} 
					updChanges={(e)=>updFrm("weight",e)}
				/>
				<div className="flexSpace"/>
				
				
			</div>



			<div className="_dsplFlx  spaceAround flxWrp " style={{marginTop: 10}}>
				<div className="flexSpace"/>
				
				
				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["genre"]}
						lbl_empty={"Sexo"} 
						list={[
							{label: "Mujer", id:"Female"},
							{label: "Hombre", id:"Male"}
							
						]} 
						onSelect={(e)=>updFrm("genre",e.id)}
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>	
				<div className="flexSpace"/>
			

				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["maritalStatus"]}
						lbl_empty={"Estado Civil"} 
						list={[
							{label: "Soltero", id:"Single"},
							{label: "Casado", id:"Married"},
							{label: "Divorciado", id:"Divorced"},
							{label: "Viudo", id:"Widowed"}
						]} 
						onSelect={(e)=>updFrm("maritalStatus",e.id)}
						direction={"right"} 
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>	
				<div className="flexSpace"/>
				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["ethnicity"]}
						lbl_empty={"Ethnicity"} 
						list={
							[
								{label: "Hispanic or Latino", id:"Hispanic or Latino"},
								{label: "Not Hispanic or Latino", id:"Not Hispanic or Latino"},
							]
						}
						onSelect={(e)=>updFrm("ethnicity",e.id)} 
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>	
				<div className="flexSpace"/>
				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["race"]}
						lbl_empty={"Raza"} 
						list={
							[
								{label: "White", id:"White"},
								{label: "Asian", id:"Asian"},
								{label: "Black or African American", id:"Black or African American"},
								{label: "American Indian or Alaska Native", id:"American Indian or Alaska Native"},
								{label: "Native Hawaiian or Other Pacific Islander", id:"Native Hawaiian or Other Pacific Islander"},
							]
						}
						onSelect={(e)=>updFrm("race",e.id)} 
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>	
				<div className="flexSpace"/>
				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["hairColor"]}
						lbl_empty={"Hair Color"} 
						list={
							[
								{label: "Bald", id:"Bald"},
								{label: "Black", id:"Black"},
								{label: "Blond", id:"Blond"},
								{label: "Brown", id:"Brown"},
								{label: "Gray", id:"Gray"},
								{label: "Red", id:"Red"},
								{label: "Sandy", id:"Sandy"},
								{label: "White", id:"White"},
								{label: "Unknown/ Other", id:"Unknown/ Other"},
							]
						}
						onSelect={(e)=>updFrm("hairColor",e.id)} 
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>	
				<div className="flexSpace"/>
				
				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["eyesColor"]}
						lbl_empty={"Eyes Color"} 
						list={
							[
								{label: "Black", id:"Black"},
								{label: "Blue", id:"Blue"},
								{label: "Brown", id:"Brown"},
								{label: "Gray", id:"Gray"},
								{label: "Green", id:"Green"},
								{label: "Hazel", id:"Hazel"},
								{label: "Maroon", id:"Maroon"},
								{label: "Pink", id:"Pink"},
								{label: "Unknown/ Other", id:"Unknown/ Other"},
							]
						}
						onSelect={(e)=>updFrm("eyesColor",e.id)} 
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>	
				<div className="flexSpace"/>
	


			</div>
			
			<div className="separator"/>


			

			<p className="group_title">
				Lugar de Nacimiento 
			</p>
			<div className="_dsplFlx spaceAround flxWrp"  style={{marginBottom: 20}}> 
				
				<TextInput 
					init={getStore(frmNm)?.["placeOfBirth"]?.["city"]} 
					label={"Municipio"} 
					width={200} 
					updChanges={(e)=>updFrm("city",e, "placeOfBirth")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["placeOfBirth"]?.["state"]} 
					label={"Provincia"} 
					width={200} 
					updChanges={(e)=>updFrm("state",e, "placeOfBirth")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["placeOfBirth"]?.["country"]} 
					label={"Pais de Nacimiento"} 
					width={200} 
					updChanges={(e)=>updFrm("country",e, "placeOfBirth")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["countryOfCitizenship"]} 
					label={"Ciudadania"} 
					width={200} 
					updChanges={(e)=>updFrm("countryOfCitizenship",e)}
				/>
			</div>
			<div className="_dsplFlx spaceAround flxWrp" style={{marginBottom: 20}}> 

				<div className="_dsplFlx " style={{marginTop: 40}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["isInUSA"]}
						keyCode={57}
						updChange={(e)=>updFrm("isInUSA",e)}
						color={"var(--primary)"}
					/>
					<span className={`checklabel`}>
						{"esta en USA"}
					</span>
				</div>
				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["state"]} 
					label={"Estado de Recidencia Actual"} 
					width={200} 
					updChanges={(e)=>updFrm("state",e, "currentLocation")}
				/>

				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["country"]} 
					label={"Pais de Recidencia Actual"} 
					width={200} 
					updChanges={(e)=>updFrm("country",e, "currentLocation")}
				/>

				
			</div>

		

			<div className="separator"/>



			<div className="_dsplFlx spaceAround flxWrp" style={{marginBottom: 40}}> 
				<p className="group_title">
					Corte
				</p>
				<div className="_dsplFlx " style={{marginTop: 20}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["isInCourt"]}
						keyCode={37}
						updChange={(e)=>updFrm("isInCourt",e)}
						color={"var(--primary)"}
					/>
					<span className={`checklabel`}>
						{"Tiene corte"}
					</span>
				</div>
			
			</div>
			{getStore(frmNm)?.["isInCourt"]? 
			<div className="_dsplFlx spaceAround flxWrp"> 
				<TextInput  
					init={getStore(frmNm)?.["judgeName"]} 
					label={"Judge Name"} 
					width={300} 
					updChanges={(e)=>updFrm("judgeName",e)}
				/>
				
				<TextInput  
					init={getStore(frmNm)?.["court_name"]} 
					label={"Court Name "} 
					width={480} 
					updChanges={(e)=>updFrm("court_name",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["court_address"]} 
					label={"Address"} 
					width={480} 
					updChanges={(e)=>updFrm("court_address",e)}
				/>
				<TextInput 
					init={getStore(frmNm)?.["court_city"]} 
					label={"City, State, Zipcode"} 
					width={480} 
					updChanges={(e)=>updFrm("court_city",e)}
				/>
			</div> 
			:null}
			{diff?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Actualizar"} clickHandler={print}/>
						
					</div>
				</div>
			):<div className="card"/>}
		</div>
	);
};

export default UpdClientInfo;




const GrayButton  = ({ clickHandler, label }) => {
	return (
		<div className=" jaqJnq_hrm1"  >
			<button className="gHAsFI_hrm1 dqnOfN jUrKkb" onClick={clickHandler}>
				<span className=" jaqJnq_hrm1" >
					{label}
				</span>
			</button>
		</div>
	)
}





